module RefModule(rst, clk, test, sync, freq, o);parameter WID = 32; 
input rst;
input clk;
input test;
input sync;
input [WID-1:0] freq;   
output [WID-1:0] o;

reg [WID-1:0] obf_acc;

always @(posedge clk)
if (rst)
    obf_acc <= 0;
else begin
    if (~test) begin
        if (sync)
            obf_acc <= 0;
        else
            obf_acc <= obf_acc + freq;
    end
    else
        obf_acc <= 0;
end

assign o = obf_acc;

endmodule
